*	SBC6800 ECHOBACK
*	BY INTERRUPT
*
*	ADDRESS
ACIACS	EQU	$8018
ACIADA	EQU	$8019
ROM	EQU	$E000
RAM	EQU	$0000
STACK	EQU	$1FFF
*
*	RECIVE BUFFER
BUFSIZ	EQU	$10
BUFMSK	EQU	$0F
*
*	RAM AREA
	ORG	RAM
RECCNT	RMB	1
RECROF	RMB	1
RECWOF	RMB	1
RECPTR	RMB	2
RECADR	RMB	2
RECBUF	RMB	BUFSIZ
*
*	ROM AREA
	ORG	ROM
*
*	ACIA RECIVE INTERRUPT
INTSCI	LDAA	ACIACS
	ASRA
	BCC	INTSCI1
	LDAB	ACIADA
*
*	COUNT UP
	LDAA	RECCNT
	CMPA	#BUFSIZ
	BEQ	INTSCI1
	INCA
	STAA	RECCNT
*
*	SETUP INDEX
	LDAA	RECWOF
	ADDA	RECADR+1
	STAA	RECPTR+1
	LDAA	#$00
	ADCA	RECADR
	STAA	RECPTR
	LDX	RECPTR
*
*	TRANSFER
	STAB	X
*
*	UPDATE OFFSET
	LDAA	RECWOF
	INCA
	ANDA	#BUFMSK
	STAA	RECWOF
INTSCI1	RTI
*
*	INPUT CHAR
INCH	LDAA	ACIACS
	ASRA
	BCC	INCH	RECEIVE NOT READY
	LDAA	ACIADA	INPUT CHARACTER
	RTS
*
*	INPUT CHAR FROM BUFFER
INCHB	LDAA	RECCNT
	CMPA	#$00
	BEQ	INCHB
	DECA
	STAA	RECCNT
*
*	SETUP INDEX
	SEI		DISABLE INTERRUPT
	LDAA	RECROF
	ADDA	RECADR+1
	STAA	RECPTR+1
	LDAA	#$00
	ADCA	RECADR
	STAA	RECPTR
	LDX	RECPTR
*
*	UPDATE OFFSET
	LDAA	RECROF
	INCA
	ANDA	#BUFMSK
	STAA	RECROF
*
*	TRANSFER
	LDAA	X
	CLI
	RTS
*
*	OUTPUT CHAR
OUTCH	PSH	A
OUTCH1	LDAA	ACIACS
	ASRA
	ASRA
	BCC	OUTCH1
	PULA
	STAA	ACIADA
	RTS
*
*	OUTPUT STRING
OUTS	PSHA
OUTS1	LDAA	X
	CMPA	#00
	BEQ	OUTS2
	JSR	OUTCH
	INX
	BRA	OUTS1
OUTS2	PULA
	RTS
*
*	MESSAGE
MESG	FCB	$0D
	FCB	$0A
	FCC	'KEYIN THEN ECHO'
	FCB	$0D
	FCB	$0A
	FCB	$00
*
*	POWER ON SEQUENCE
START	LDS	#STACK
	LDX	#RECBUF
	STX	RECADR
	CLR	RECCNT
	CLR	RECROF
	CLR	RECWOF
*
*	ACIA INITIALIZE
	LDAA	#$03	RESET CODE
	STAA	ACIACS
	LDAA	#%10010101	8N1 INTERRUPT
	STAA	ACIACS
	CLI		ENABLE INTERRUPT
*
*	OPENNING MESSAGE
	LDX	#MESG
	JSR	OUTS
*
*	KEYIN AND ECHO
LOOP	JSR	INCHB
	JSR	OUTCH
	BRA	LOOP
*
*	UNUSE INTERRUPT
UUINT	RTI
*
*	VECTOR
	ORG	$FFF8
VIRQ	FDB	INTSCI
VSWI	FDB	UUINT
VNMI	FDB	UUINT
VRES	FDB	START
	END
